"use client"
import './kakaomap.css'
import React, { useEffect } from 'react'

declare global {
    interface Window {
        kakao: any;
    }
}

const KAKAO_KEY = process.env.NEXT_PUBLIC_KAKAO_APP_KEY;

export default function KakaoMap() {
useEffect(()=>{
    if(!KAKAO_KEY){
        console.error("API키를 확인해주세요");
        return;
    }

    const script = document.createElement("script");
    script.src = `//dapi.kakao.com/v2/maps/sdk.js?appkey=${KAKAO_KEY}&autoload=false&libraries=services`;
    script.async = true;

    document.head.appendChild(script);
    
    script.onload = () => {
        window.kakao.maps.load(()=>{
            initialzeMap();
        });
    };

    return () => {
        // watch this 
        document.head.removeChild(script);
    };
},[]);

const initialzeMap = () => {
    const container = document.getElementById('map');

    if(!container) 
        return;
    const defaultCenter = new window.kakao.maps.LatLng(37.566826, 126.9786567);
    const options = {
      center: defaultCenter,
      level: 4,
    };
    const map = new window.kakao.maps.Map(container, options);

    // Bring My Position
    if(navigator.geolocation){
        navigator.geolocation.getCurrentPosition(
            (pos) => {
                const lat = pos.coords.latitude;
                const lon = pos.coords.longitude;
                const userPosition = new window.kakao.map.LatLng(lat, lon);

                map.setCenter(userPosition);
                displayUserMarker(map, userPosition);
                searchPharmacies(map, userPosition);
            },
            (err) => {
                console.error("위치 권한 거부됨",err);
                searchPharmacies(map, defaultCenter);
            }
        );
    } else {
        searchPharmacies(map, defaultCenter);
    }
};

const displayUserMarker = (map:any, position: any) =>{
    const imageSrc = "https://t1.daumcdn.net/localimg/localimages/07/mapapidoc/marker_red.png"; 
    const imageSize = new window.kakao.maps.Size(64, 69);
    const imageOption = { offset: new window.kakao.maps.Point(27, 69) };

    const markerImage = new window.kakao.maps.MarkerImage(imageSrc, imageSize, imageOption);
    new window.kakao.maps.Marker({
      position: position,
      image: markerImage,
      map: map,
    });
  };

  const searchPharmacies = (map: any, centerPosition: any) => {
    const ps = new window.kakao.maps.services.Places();

    ps.categorySearch('PM9', (data: any[], status: any) => {
      if (status === window.kakao.maps.services.Status.OK) {
        displayPlaces(data, map);
      }
    },{
        location: centerPosition,
        radius: 2000,
        useMapBounds: true,
    });
  };

  // marker 
  const displayPlaces = (places: any[], map: any) => {
    const infowindow = new window.kakao.maps.InfoWindow({ zIndex: 1 });

    for (let i = 0; i < places.length; i++) {
      const place = places[i];
      const marker = new window.kakao.maps.Marker({
        map: map,
        position: new window.kakao.maps.LatLng(place.y, place.x),
      });

      // 마커 클릭 이벤트
      window.kakao.maps.event.addListener(marker, 'click', function() {
        const content = `
          <div class="custom-infowindow">
            <strong>${place.place_name}</strong>
            <p>${place.phone || '전화번호 없음'}</p>
            <a href="${place.place_url}" target="_blank">상세보기</a>
          </div>
        `;
        infowindow.setContent(content);
        infowindow.open(map, marker);
      });
    }
  }
    
    return (
      <div className="map-wrap">
          <div className="kakao-map"></div>
      </div>
    );
  };



